class Solution:
    def exist(self, board: list[list[str]], word: str) -> bool:
        rows = len(board)
        if rows == 0:
            return False

        cols = len(board[0])
        if cols == 0 and len(word) > 0:
            return False

        word_len = len(word)
        if word_len == 0:
            return True

        # Directions: (dr, dc) for (row_change, col_change)
        # Covers horizontal, vertical, and both diagonals, in forward and reverse.
        directions = [
            (0, 1), (0, -1),  # Horizontal (right, left)
            (1, 0), (-1, 0),  # Vertical (down, up)
            (1, 1), (1, -1),  # Diagonal (down-right, down-left)
            (-1, 1), (-1, -1) # Diagonal (up-right, up-left)
        ]

        # Helper function to check if the word can be formed starting from (r, c)
        # in a specific direction (dr, dc)
        def search_from_start_and_direction(r_start: int, c_start: int, dr: int, dc: int) -> bool:
            for k in range(word_len):
                curr_r = r_start + k * dr
                curr_c = c_start + k * dc

                # Check boundaries: if the current position is out of the board
                if not (0 <= curr_r < rows and 0 <= curr_c < cols):
                    return False
                # Check character match: if the character at the current position
                # does not match the k-th character of the word
                if board[curr_r][curr_c] != word[k]:
                    return False
            return True # If the loop completes, all characters matched in sequence

        # Iterate over each cell in the board
        for r in range(rows):
            for c in range(cols):
                # Optimization: if the first character of the word doesn't match
                # the current cell, we can't start the word from here.
                if board[r][c] == word[0]:
                    # Try all 8 possible directions from the current cell
                    for dr, dc in directions:
                        if search_from_start_and_direction(r, c, dr, dc):
                            return True # Word found

        return False # Word not found after checking all possibilities
